  var DECIMALS = 3;
  var FROM = "g";
  var TO = "oz";

  function round(n) {
    var f = Math.pow(10, DECIMALS);
    return Math.round((n + Number.EPSILON) * f) / f;
  }
  function fmt(n) {
    return round(n).toLocaleString('en-US', { maximumFractionDigits: DECIMALS });
  }

